import { FiFolder } from 'react-icons/fi';
const ProjectsPage = () => (
  <div className="flex flex-col gap-6">
    <h1 className="text-2xl font-bold text-gray-900">Projets</h1>
    <div className="card flex flex-col items-center justify-center py-24 gap-4 text-gray-400">
      <FiFolder size={48} />
      <p className="text-lg font-medium">Gestion des projets</p>
      <p className="text-sm">Connectez ce composant au project-service (port 3002)</p>
    </div>
  </div>
);
export default ProjectsPage;
